/***********************
  Nav Component
 ***********************/

import { Menu } from "antd";
import Link from "next/link";
import { useRouter } from "next/router";

const Nav = (props) => {
  const router = useRouter();
  const menu = [
    {
      title: "Home",
      url: "/",
      section: "navbar",
    },
    {
      title: "Blog",
      url: "/blog",
      section: "projects",
    },
    {
      title: "Contact",
      url: "/contact",
    },
  ];

  return (
    <>
    <header className="header fixed-header">
        <div className="container">
          <div className="row">
            <div className="col-lg-4 col-8">
              <a href="#"><img className="site-logo img-responsive" src="./static/img/jakarea-parvez.png" alt=""/></a>
            </div>
            <div className="col-lg-8 col-4">
              <nav className="navbar navbar-expand-lg">
                <div className="navbar-header">
                  <button className="navbar-toggler" type="button" data-toggle="collapse" data-target="#navbarSupportedContent"
                    aria-controls="navbarSupportedContent" aria-expanded="false" aria-label="Toggle navigation">
                    <span className="navbar-toggler-icon"></span>
                    <i className="fa fa-bars"></i>
                  </button>
                </div>
                <ul className="nav navbar-nav navbar-right">
                  <li className="current"><Link href="#">About</Link></li>
                  <li><Link href="blog">Blog</Link></li>
                  <li><Link href="service">Service</Link></li>
                  <li><Link href="projects">Projects</Link></li>
              </ul>
              </nav>
            </div>
          </div>
        </div>

      </header>
      <nav id="navbar">
        <div className="nav-wrapper">
          <p className="brand">Jakarea Parvez </p>

          <Menu
            theme="light"
            mode="horizontal"
            // defaultSelectedKeys={["1"]}
            // selectedKeys={["1"]}
            className="menu"
          >
            {menu.map((item) => (
              <Menu.Item
                key={item.title}
                className={
                  item.url === router.pathname ? "ant-menu-item-selected" : ""
                }
              >
                <Link href={item.url}>{item.title}</Link>
              </Menu.Item>
            ))}
          </Menu>
        </div>
      </nav>
    </>
  );
};

export default Nav;
